mapper.select:
SELECT cfg.id, cfg.provider_code, cfg.provider_name, cfg.api_base_url, cfg.token_mask, cfg.default_model, cfg.connect_status, cfg.status, cfg.remark, cfg.update_time, COALESCE(model.model_count, 0) AS model_count FROM ai_provider_config cfg LEFT JOIN ( SELECT provider_config_id, COUNT(1) AS model_count FROM ai_provider_model GROUP BY provider_config_id ) model ON model.provider_config_id = cfg.id WHERE cfg.is_deleted = FALSE
AND ( cfg.provider_code LIKE CONCAT('%', #{request.keywords}, '%') OR cfg.provider_name LIKE CONCAT('%', #{request.keywords}, '%') )
AND cfg.status = #{request.status}
AND cfg.connect_status = #{request.connectStatus}
ORDER BY cfg.update_time DESC, cfg.id DESC

