) VALUES (
    #{providerCode}, #{providerName}, #{apiBaseUrl}, #{apiTokenCipher}, #{tokenMask},
    #{defaultModel}, #{connectStatus}, #{status}, #{remark}, #{createTime}, #{updateTime},
    #{createUser}, #{updateUser}, #{isDeleted}
)

mapper.update:
UPDATE ai_provider_config
SET status = #{status},
    update_time = #{updateTime},
    update_user = #{updateUser}
WHERE id = #{id}
  AND is_deleted = FALSE
